1	export type Item = {
2	  type: string;
3	  material?: string;
4	  enchantment?: number;
5	  cursed?: boolean;
6	};
7	
8	export type QuoteStep = {
9	  op: "quote";
10	  items: Item[];
11	};
12	
13	export type Step = QuoteStep;
14	
15	export type Scenario = {
16	  customer: { yearsWithMHPCO: number };
17	  steps: Step[];
18	};
19	
20	export type QuoteResult = { premium: number };
21	export type StepResult = QuoteResult;
22	
23	export type ScenarioResult = {
24	  results: StepResult[];
25	};
26	
27	const PROCESSING_FEE = 5;
28	const FIRST_CONTRACT_SURCHARGE_RATE = 0.1;
29	const BLOCK_OF_THREE_DISCOUNT = 15;
30	
31	const BASE_PREMIUM: Record<string, number> = {
32	  sword: 100,
33	  amulet: 60,
34	  staff: 80,
35	  potion: 40,
36	  rune: 25,
37	};
38	
39	const runeBasePremium = (runeCount: number): number => {
40	  const ungrouped = runeCount * BASE_PREMIUM.rune;
41	  return runeCount === 3 ? ungrouped - BLOCK_OF_THREE_DISCOUNT : ungrouped;
42	};
43	
44	const sumBasePremiums = (items: Item[]): number => {
45	  const runes = items.filter((i) => i.type === "rune");
46	  const others = items.filter((i) => i.type !== "rune");
47	  const otherBase = others.reduce((sum, item) => sum + BASE_PREMIUM[item.type], 0);
48	  return runeBasePremium(runes.length) + otherBase;
49	};
50	
51	const quote = (step: QuoteStep): QuoteResult => {
52	  const itemsBase = sumBasePremiums(step.items);
53	  const firstContractSurcharge = itemsBase * FIRST_CONTRACT_SURCHARGE_RATE;
54	  const premium = itemsBase + firstContractSurcharge + PROCESSING_FEE;
55	  return { premium };
56	};
57	
58	export const runScenario = (scenario: Scenario): ScenarioResult => {
59	  const results = scenario.steps.map(quote);
60	  return { results };
61	};
